241→    // used by "yield" implementation
242→    internal fun dispatchYield(context: CoroutineContext, value: T) {
243→        _state = value
244→        resumeMode = MODE_CANCELLABLE
245→        dispatcher.dispatchYield(context, this)
246→    }
