132→
133→        override fun schedule(command: Runnable, delay: Long, unit: TimeUnit): ScheduledFuture<*> {
134→            submittedTasks++
135→            if (submittedTasks > acceptTasks) throw RejectedExecutionException()
136→            val wrapper = Runnable {
137→                runningTask.value = true
138→                try {
139→                    command.run()
140→                } finally {
141→                    runningTask.value = false
142→                }
143→            }
144→            return super.schedule(wrapper, delay, unit)
145→        }
146→
