                .collect {
                    expectUnreached()
                }
        }
        assertEquals("Dispatcher throws", exception.message)
    }

    /**
     * Tests that flowOn with buffer and a throwing dispatcher properly propagates the exception.
     */
    @Test
    fun testFlowOnBufferedWithThrowingDispatcher() = runTest {
        val exception = assertFailsWith<IllegalStateException> {
            flowOf(1, 2, 3)
                .buffer()
                .flowOn(ThrowingDispatcher)
                .collect {
                    expectUnreached()
                }
        }
        assertEquals("Dispatcher throws", exception.message)
    }

    /**
     * Tests that when ATOMIC start mode is used with a throwing dispatcher,
     * the exception is properly propagated.
     */
    @Test
    fun testLaunchAtomicWithThrowingDispatcher() = runTest {
        val job = launch(ThrowingDispatcher, start = CoroutineStart.ATOMIC) {
            expectUnreached()
        }
        // Job should be cancelled due to the dispatcher exception
        assertTrue(job.isCancelled)
    }

    /**
     * Tests that produce with ATOMIC start mode and a throwing dispatcher
     * properly closes the channel with an exception.
     */
    @Test
    fun testProduceAtomicWithThrowingDispatcher() = runTest {
        val channel = produce<Int>(ThrowingDispatcher, start = CoroutineStart.ATOMIC) {
            expectUnreached()
        }
        val exception = assertFailsWith<IllegalStateException> {
            channel.receive()
        }
        assertEquals("Dispatcher throws", exception.message)
    }

    /**
     * A dispatcher that always throws when dispatch is called.
     * This simulates the case when Dispatchers.Main.immediate is used
     * but Main dispatcher is not available in the classpath.
     */
    private object ThrowingDispatcher : CoroutineDispatcher() {
        override fun dispatch(context: CoroutineContext, block: Runnable) {
            throw IllegalStateException("Dispatcher throws")
        }
    }
}
"}

